            let qIndex = 0;
            for (const dim of dims) { for (let i = 0; i < 8; i++) { if (answers[qIndex] !== undefined) { if (dim === 'EI') { if (answers[qIndex] === 0) scores.E++; else scores.I++; } else if (dim === 'SN') { if (answers[qIndex] === 0) scores.S++; else scores.N++; } else if (dim === 'TF') { if (answers[qIndex] === 0) scores.T++; else scores.F++; } else if (dim === 'JP') { if (answers[qIndex] === 0) scores.J++; else scores.P++; } } qIndex++; } }
